import{_ as i,c as s,a7 as a,o as t}from"./chunks/framework.BKiDQeMP.js";const k=JSON.parse('{"title":"FAIR ML Model Packaging","description":"","frontmatter":{"order":2},"headers":[],"relativePath":"Community and Best Practices/Data and Workflow Best Practices/Workflows/fair-ml-models.md","filePath":"Community and Best Practices/Data and Workflow Best Practices/Workflows/fair-ml-models.md"}'),n={name:"Community and Best Practices/Data and Workflow Best Practices/Workflows/fair-ml-models.md"};function l(o,e,r,h,d,p){return t(),s("div",null,e[0]||(e[0]=[a(`<h1 id="fair-ml-model-packaging" tabindex="-1">FAIR ML Model Packaging <a class="header-anchor" href="#fair-ml-model-packaging" aria-label="Permalink to &quot;FAIR ML Model Packaging&quot;">​</a></h1><p>Machine-learning models published through EarthCODE should be treated as reusable workflow artefacts. The model files, source code, runtime environment, metadata, and example inference path should be clear enough that another user can inspect the model and run it in a compatible Python environment.</p><p>This guide complements the general <a href="./workflow-best-practices">Workflow Best Practices</a> with a practical packaging pattern for trained Earth observation models. The aim is not to create a complex model registry. The aim is to make every model package predictable: users should be able to find the weights, understand the intended inputs and outputs, install the runtime, and run inference without reverse-engineering the original training notebook.</p><div class="tip custom-block"><p class="custom-block-title">Minimum expectation</p><p>At publication time, a model package should include a model card, a pinned runtime environment, at least one reproducible inference artefact, and validation notes showing that the artefact matches the model described in the documentation.</p></div><h2 id="recommended-package-layout" tabindex="-1">Recommended Package Layout <a class="header-anchor" href="#recommended-package-layout" aria-label="Permalink to &quot;Recommended Package Layout&quot;">​</a></h2><p>Use this layout for model files stored in a Git repository, release bundle, or PRR storage referenced in the Open Science Catalog.</p><table tabindex="0"><thead><tr><th>File</th><th style="text-align:right;">Status</th><th>Purpose</th></tr></thead><tbody><tr><td><code>README.md</code></td><td style="text-align:right;">Required</td><td>Human-readable model card describing what the model predicts, expected inputs, outputs, provenance, caveats, and reuse conditions.</td></tr><tr><td><code>requirements.txt</code>, <code>environment.yml</code>, or <code>Dockerfile</code></td><td style="text-align:right;">Required</td><td>Pinned runtime definition for loading the model and running inference. Use a container when system libraries or non-Python dependencies matter.</td></tr><tr><td><code>model.safetensors</code></td><td style="text-align:right;">Recommended</td><td>PyTorch state dictionary in a non-pickle format. Useful for users who want to reconstruct the architecture in Python.</td></tr><tr><td><code>model.onnx</code></td><td style="text-align:right;">Recommended</td><td>Portable inference graph for users who want to run inference with ONNX Runtime and avoid custom model-loading code.</td></tr><tr><td><code>inference.py</code></td><td style="text-align:right;">Recommended</td><td>Small script or module that performs preprocessing, model loading, inference, and postprocessing.</td></tr><tr><td><code>example_inference.ipynb</code></td><td style="text-align:right;">Optional</td><td>Runnable demonstration for users who learn best from a notebook or need an end-to-end example.</td></tr><tr><td><code>config.json</code></td><td style="text-align:right;">Optional</td><td>Machine-readable model configuration, but only if downstream tooling or inference code actually reads it.</td></tr><tr><td><code>labels.json</code></td><td style="text-align:right;">Optional</td><td>Class labels or output names, useful when labels are not already encoded in the README or model metadata.</td></tr></tbody></table><p>If your model is not PyTorch-based, use the equivalent open, documented, and validated artefact for that framework. Avoid publishing only opaque checkpoint files such as <code>.pt</code>, <code>.pkl</code>, or framework-specific archives unless the loading code and environment are also provided.</p><h2 id="write-a-model-card" tabindex="-1">Write a Model Card <a class="header-anchor" href="#write-a-model-card" aria-label="Permalink to &quot;Write a Model Card&quot;">​</a></h2><p>The <code>README.md</code> should be short, but complete enough that the model is usable without opening the training code. Treat it as the model card for the package.</p><p>Include:</p><ul><li>model name, version, authors, project, and contact information;</li><li>what the model predicts and the scientific use case it supports;</li><li>intended use, out-of-scope use, and known limitations;</li><li>expected input shape, for example <code>N,4,128,128</code>;</li><li>expected channel order, units, normalization, nodata handling, and spatial or temporal assumptions;</li><li>output meaning, for example logits over six cloud morphology classes;</li><li>class names or output variables in order;</li><li>training data sources, validation data sources, and relevant EarthCODE Products or Experiments;</li><li>source repository, release tag, commit hash, and license;</li><li>exact inference command or notebook entry point;</li><li>data caveats, domain limits, uncertainty notes, or bias risks that may affect reuse.</li></ul><p>Do not bury required preprocessing steps in prose if users need exact operations. Put exact preprocessing in <code>inference.py</code>, a reusable function, or a small inference notebook.</p><h2 id="define-the-runtime" tabindex="-1">Define the Runtime <a class="header-anchor" href="#define-the-runtime" aria-label="Permalink to &quot;Define the Runtime&quot;">​</a></h2><p>Pin the dependencies used to export and validate the model. A minimal <code>requirements.txt</code> for a validated Python model package might look like this:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>torch==2.11.0</span></span>
<span class="line"><span>torchvision==0.26.0</span></span>
<span class="line"><span>timm==1.0.27</span></span>
<span class="line"><span>safetensors==0.7.0</span></span>
<span class="line"><span>onnxruntime==1.24.2</span></span>
<span class="line"><span>numpy==2.2.6</span></span></code></pre></div><p>Replace these example versions with the versions you actually used and tested. If the model can be used through ONNX only, users may not need <code>torch</code>, <code>torchvision</code>, <code>timm</code>, or <code>safetensors</code> for inference. Still include the full environment used to create and validate the package, unless you intentionally maintain separate export and inference environments.</p><p>For models intended to run across EarthCODE platforms, a <code>Dockerfile</code> or OGC Application Package can make the runtime more reproducible than a Python requirements file alone. Use the same principle as for any workflow: the published artefact should run from a clean environment without manual setup steps.</p><h2 id="publish-safe-weights" tabindex="-1">Publish Safe Weights <a class="header-anchor" href="#publish-safe-weights" aria-label="Permalink to &quot;Publish Safe Weights&quot;">​</a></h2><p>Use <code>model.safetensors</code> when you want to support PyTorch users while avoiding pickle-based checkpoint loading. The file should contain the model state dictionary and lightweight metadata.</p><p>Recommended metadata includes:</p><ul><li>model identifier and version;</li><li>architecture name;</li><li>input shape;</li><li>channel names and units;</li><li>output names or class names;</li><li>license and source repository;</li><li>training or validation data references, where practical.</li></ul><p>Example:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> safetensors.torch </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> save_file</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">metadata </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;model_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;earthcode-goes-cloud-regime-classifier&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;v0.1.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;architecture&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;timm.resnet50d&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;input_shape&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;N,4,128,128&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;channel_names&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;BT15_minus_BT14,BT14_minus_BT11,BT14,COD&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;class_names&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Solid stratus,Closed MCC,Open MCC,Disorganized MCC,Clustered Cu,Suppressed Cu&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;license&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Apache-2.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">save_file(weights, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;model.safetensors&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">metadata</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">metadata)</span></span></code></pre></div><p>Keep metadata values compact and machine-readable. If the metadata becomes long or nested, store it in the model card or in a configuration file that the inference code reads.</p><h2 id="provide-a-portable-inference-artefact" tabindex="-1">Provide a Portable Inference Artefact <a class="header-anchor" href="#provide-a-portable-inference-artefact" aria-label="Permalink to &quot;Provide a Portable Inference Artefact&quot;">​</a></h2><p>Use <code>model.onnx</code> when you want a common inference artefact that does not require users to reconstruct the PyTorch model class.</p><p>The ONNX model should:</p><ul><li>use stable input and output names, for example <code>input</code> and <code>logits</code>;</li><li>support a dynamic batch dimension when batch size should vary;</li><li>define the expected tensor dtype;</li><li>be exported from the same model version described in the README;</li><li>be validated against the framework-native model.</li></ul><p>Example export shape:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dummy_input </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torch.zeros((</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">128</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">128</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">dtype</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">torch.float32)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">torch.onnx.export(</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    model,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    dummy_input,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;model.onnx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    input_names</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;input&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    output_names</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;logits&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    dynamic_axes</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;input&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;batch&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;logits&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;batch&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}},</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    opset_version</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">17</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    dynamo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">False</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>If the model uses operations that are not supported by ONNX Runtime, document that clearly and provide the most portable alternative available for the framework.</p><h2 id="validate-before-publishing" tabindex="-1">Validate Before Publishing <a class="header-anchor" href="#validate-before-publishing" aria-label="Permalink to &quot;Validate Before Publishing&quot;">​</a></h2><p>Before publishing a model package, check that:</p><ul><li>the runtime can be recreated from the published environment file or container;</li><li><code>model.safetensors</code> loads into the expected architecture;</li><li><code>model.onnx</code> runs with ONNX Runtime, if provided;</li><li>framework-native and ONNX outputs are close for the same test input;</li><li>the inference example runs from start to finish in a clean environment;</li><li>README input channels, preprocessing, output names, and class order match the actual model;</li><li>no credentials, private paths, or unpublished data are required to run inference;</li><li>the package has a clear license and citation guidance.</li></ul><p>A minimal output check is:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> numpy </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> np</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">np.testing.assert_allclose(pytorch_logits, onnx_logits, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">rtol</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1e-4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">atol</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1e-4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>For classification models, also test that label ordering is consistent between the README, metadata, and inference code. For regression or segmentation models, check output shape, units, nodata handling, and geospatial alignment.</p><h2 id="publishing-to-earthcode" tabindex="-1">Publishing to EarthCODE <a class="header-anchor" href="#publishing-to-earthcode" aria-label="Permalink to &quot;Publishing to EarthCODE&quot;">​</a></h2><p>How you publish a model in EarthCODE depends on what you want others to discover, reuse, or reproduce.</p><ul><li>If the trained model is the research output, publish the packaged model as an EarthCODE Product. The Product should point to the model artefacts, model card, version, license, and validation evidence.</li><li>If you are publishing the full process that produced or uses the model, describe it as a provenance chain: <ul><li>Workflow: the versioned training or inference code, runtime environment, and execution instructions.</li><li>Products: the input training data, exported model package, and any generated modelled data.</li><li>Experiment: the specific run that links the Workflow, configuration, input Products, and output Products.</li></ul></li></ul><p>This makes it clear whether users are reusing a trained model directly, rerunning the modelling workflow, or tracing a published dataset back to the code, data, and model version that produced it.</p>`,42)]))}const u=i(n,[["render",l]]);export{k as __pageData,u as default};
